#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long S, N; scanf("%lld %lld", &S, &N);
        long long q = S / N;
        long long r = S % N;
        long long ans = q + r/2 + r%2;
        printf("%lld\n", ans);
    }
    return 0;
}

